#include<bits/stdc++.h>
using namespace std;
int n,s[200010],a[200010];
vector<int> v[200010];
bool vis[200010];
int lowbit(int x)
{
	return x&-x;
}
void update(int x,int v)
{
	for(int i=x;i<=n*2;i+=lowbit(i))
	{
		s[i]+=v;
	}
}
int query(int x)
{
	int ans=0;
	for(int i=x;i>=1;i-=lowbit(i))
	{
		ans+=s[i];
	}
	return ans;
}
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n*2;i++)
	{
		scanf("%d",&a[i]);
		v[a[i]+n].push_back(i);
		update(i,1);
	}
	long long ans=0;
	for(int i=n*2;i>=1;i--)
	{
		if(vis[i])
		{
			continue;
		}
		v[a[i]+n].pop_back();
		int t=v[-a[i]+n].back();
		v[-a[i]+n].pop_back();
		vis[t]=1;
		update(t,-1);
		ans+=query(i-1)-query(t-1);
		if(a[i]<0)
		{
			ans++;
		}
	}
	printf("%lld",ans);
	return 0;
}
